diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index 2d7524e8018b..aa247db76dad 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -1351,17 +1351,34 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   };
   const APInt *Mask1 = nullptr, *Mask2 = nullptr;
   bool MatchedAnd1 = false, MatchedAnd2 = false;
-  if (V1 != V2 && AreContiguousRangePredicates(Pred1, Pred2, IsAnd)) {
+  if (V1 != V2) {
     Value *X;
-    if (match(V1, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask1)))) &&
-        C1->getBitWidth() == C2->getBitWidth() && *C1 == *C2 + 1 &&
-        C1->uge(Mask1->abs()) && C1->isPowerOf2()) {
+    // First, handle the contiguous range pattern.
+    if (AreContiguousRangePredicates(Pred1, Pred2, IsAnd)) {
+      if (match(V1, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask1)))) &&
+          C1->getBitWidth() == C2->getBitWidth() && *C1 == *C2 + 1 &&
+          C1->uge(Mask1->abs()) && C1->isPowerOf2()) {
+        MatchedAnd1 = true;
+        V1 = X;
+      }
+      if (match(V2, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask2)))) &&
+          C1->getBitWidth() == C2->getBitWidth() && *C2 == *C1 + 1 &&
+          C2->uge(Mask2->abs()) && C2->isPowerOf2()) {
+        MatchedAnd2 = true;
+        V2 = X;
+      }
+    }
+    // Additionally, handle masked equality with negated power-of-two mask
+    // for equality predicates, regardless of the other icmp.
+    if (ICmpInst::isEquality(Pred1) &&
+        match(V1, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask1)))) &&
+        C1->getBitWidth() == Mask1->getBitWidth()) {
       MatchedAnd1 = true;
       V1 = X;
     }
-    if (match(V2, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask2)))) &&
-        C1->getBitWidth() == C2->getBitWidth() && *C2 == *C1 + 1 &&
-        C2->uge(Mask2->abs()) && C2->isPowerOf2()) {
+    if (ICmpInst::isEquality(Pred2) &&
+        match(V2, m_OneUse(m_And(m_Value(X), m_NegatedPower2(Mask2)))) &&
+        C2->getBitWidth() == Mask2->getBitWidth()) {
       MatchedAnd2 = true;
       V2 = X;
     }
@@ -1370,19 +1387,27 @@ Value *InstCombinerImpl::foldAndOrOfICmpsUsingRanges(ICmpInst *ICmp1,
   if (V1 != V2)
     return nullptr;

+  CmpPredicate P1 = IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1;
   ConstantRange CR1 =
       MatchedAnd1
-          ? ConstantRange(*C1, *C1 - *Mask1)
-          : ConstantRange::makeExactICmpRegion(
-                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred1) : Pred1, *C1);
+          ? (P1 == ICmpInst::ICMP_EQ
+                 ? ConstantRange(*C1, *C1 - *Mask1)
+                 : (P1 == ICmpInst::ICMP_NE
+                        ? ConstantRange(*C1, *C1 - *Mask1).inverse()
+                        : ConstantRange(*C1, *C1 - *Mask1)))
+          : ConstantRange::makeExactICmpRegion(P1, *C1);
   if (Offset1)
     CR1 = CR1.subtract(*Offset1);

+  CmpPredicate P2 = IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2;
   ConstantRange CR2 =
       MatchedAnd2
-          ? ConstantRange(*C2, *C2 - *Mask2)
-          : ConstantRange::makeExactICmpRegion(
-                IsAnd ? ICmpInst::getInverseCmpPredicate(Pred2) : Pred2, *C2);
+          ? (P2 == ICmpInst::ICMP_EQ
+                 ? ConstantRange(*C2, *C2 - *Mask2)
+                 : (P2 == ICmpInst::ICMP_NE
+                        ? ConstantRange(*C2, *C2 - *Mask2).inverse()
+                        : ConstantRange(*C2, *C2 - *Mask2)))
+          : ConstantRange::makeExactICmpRegion(P2, *C2);
   if (Offset2)
     CR2 = CR2.subtract(*Offset2);

